const merged = $input.first().json;

const ticker = String(
  merged.ticker || ''
)
  .trim()
  .toUpperCase();

if (!ticker) {
  throw new Error(
    'Ticker is missing from Merge Analyst and News'
  );
}

const companyName = String(
  merged.company_name || ticker
).trim();

let initialAnalysis =
  merged.initial_analysis || null;

// הגנה למקרה שפלט הסוכן עדיין עטוף בתוך output
if (
  initialAnalysis &&
  initialAnalysis.output
) {
  initialAnalysis = initialAnalysis.output;
}

if (!initialAnalysis) {
  throw new Error(
    'Initial analyst result is missing'
  );
}

const newsArticles = Array.isArray(
  merged.news_articles
)
  ? merged.news_articles
  : [];

const formattedNews = newsArticles.map(
  (article, index) => {
    const summary =
      article.summary ||
      article.description ||
      article.snippet ||
      'No summary available';

    return `
===== NEWS ARTICLE ${index + 1} =====
Title: ${article.title || 'Unknown'}
Provider: ${article.news_provider || 'Unknown'}
Source: ${article.source || 'Unknown'}
Published: ${article.published || 'Unknown'}
Summary: ${summary}
URL: ${article.link || 'Unknown'}
===== END NEWS ARTICLE ${index + 1} =====
`.trim();
  }
);

const seniorAnalystInput = `
You are a senior financial analyst reviewing the conclusion of an initial financial analyst.

COMPANY INFORMATION
Ticker: ${ticker}
Company name: ${companyName}

OFFICIAL SEC ANALYSIS
Number of SEC filings analyzed:
${merged.sec_document_count || 0}

Initial analyst result:
${JSON.stringify(initialAnalysis, null, 2)}

RECENT FINANCIAL NEWS
Number of news articles:
${newsArticles.length}

${formattedNews.length
  ? formattedNews.join('\n\n')
  : 'No relevant recent financial news articles were found.'}

REVIEW TASK

1. Review whether the initial analyst's sentiment is justified.
2. Compare the SEC-based analysis with the recent financial news.
3. Identify material information the initial analyst may have missed.
4. Identify contradictions between the SEC analysis and the news.
5. Give greater weight to official SEC filings than to secondary news reports.
6. Distinguish company-specific news from articles that only mention Microsoft products or platforms.
7. Give less weight to opinion pieces, promotional headlines and weakly relevant articles.
8. Consider recency, relevance and financial materiality.
9. Decide whether the initial sentiment should be confirmed, strengthened, weakened or changed.
10. Return a final sentiment using exactly one label:
   - Strong Positive
   - Positive
   - Neutral
   - Negative
   - Strong Negative
11. Do not provide buy, sell or hold advice.
12. Return only valid structured JSON.
`.trim();

return [
  {
    json: {
      ticker,
      company_name: companyName,

      sec_document_count:
        merged.sec_document_count || 0,

      news_article_count:
        newsArticles.length,

      initial_analysis:
        initialAnalysis,

      news_articles:
        newsArticles,

      senior_analyst_input:
        seniorAnalystInput,

      senior_analyst_input_characters:
        seniorAnalystInput.length
    }
  }
];

const body = $json.body ?? $json;

const ticker = String(
  body.ticker ??
  body.ticker_input ??
  ''
)
  .trim()
  .toUpperCase();

if (!ticker) {
  throw new Error('Ticker is missing');
}

if (!/^[A-Z0-9.-]{1,10}$/.test(ticker)) {
  throw new Error('Ticker format is invalid');
}

return [
  {
    json: {
      ticker
    }
  }
];

const result = $json.output ?? $json;

function escapeHtml(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

function list(items) {
  if (!Array.isArray(items) || items.length === 0) {
    return '<p class="empty">No findings reported.</p>';
  }

  return `
    <ul>
      ${items.map(item => `<li>${escapeHtml(item)}</li>`).join('')}
    </ul>
  `;
}

const sentiment = String(result.final_sentiment || 'Neutral');

const sentimentClass = {
  'Strong Positive': 'strong-positive',
  'Positive': 'positive',
  'Neutral': 'neutral',
  'Negative': 'negative',
  'Strong Negative': 'strong-negative'
}[sentiment] || 'neutral';

const agreementText =
  result.agreement_with_initial_analyst
    ? 'Yes'
    : 'No';

const html = `
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Financial Sentiment Report</title>

  <style>
    * {
      box-sizing: border-box;
    }

    body {
      margin: 0;
      padding: 40px 20px;
      font-family: Arial, sans-serif;
      color: #172033;
      background:
        radial-gradient(circle at top left, #dbeafe 0, transparent 30%),
        radial-gradient(circle at bottom right, #ede9fe 0, transparent 30%),
        #f5f7fb;
    }

    .container {
      width: 100%;
      max-width: 1150px;
      margin: 0 auto;
    }

    .hero {
      margin-bottom: 28px;
      text-align: center;
    }

    .eyebrow {
      margin-bottom: 10px;
      color: #4f46e5;
      font-size: 13px;
      font-weight: 700;
      letter-spacing: 2px;
      text-transform: uppercase;
    }

    h1 {
      margin: 0 0 12px;
      font-size: 44px;
    }

    .subtitle {
      margin: 0;
      color: #64748b;
      font-size: 17px;
    }

    .summary-grid {
      display: grid;
      grid-template-columns: repeat(5, 1fr);
      gap: 14px;
      margin-bottom: 24px;
    }

    .summary-card,
    .card {
      border: 1px solid rgba(148, 163, 184, 0.25);
      border-radius: 20px;
      background: rgba(255, 255, 255, 0.94);
      box-shadow: 0 14px 40px rgba(30, 41, 59, 0.09);
    }

    .summary-card {
      padding: 20px;
      text-align: center;
    }

    .summary-label {
      margin-bottom: 8px;
      color: #64748b;
      font-size: 12px;
      font-weight: 700;
      letter-spacing: 1px;
      text-transform: uppercase;
    }

    .summary-value {
      font-size: 20px;
      font-weight: 800;
    }

    .sentiment {
      display: inline-block;
      padding: 8px 14px;
      border-radius: 999px;
      font-size: 16px;
      font-weight: 800;
    }

    .strong-positive {
      color: #166534;
      background: #dcfce7;
    }

    .positive {
      color: #15803d;
      background: #ecfdf5;
    }

    .neutral {
      color: #92400e;
      background: #fef3c7;
    }

    .negative {
      color: #b91c1c;
      background: #fee2e2;
    }

    .strong-negative {
      color: #7f1d1d;
      background: #fecaca;
    }

    .content-grid {
      display: grid;
      grid-template-columns: 1fr 1fr;
      gap: 20px;
    }

    .card {
      padding: 24px;
    }

    .card.full {
      grid-column: 1 / -1;
    }

    .card h2 {
      margin: 0 0 16px;
      color: #1e293b;
      font-size: 21px;
    }

    ul {
      margin: 0;
      padding-left: 20px;
    }

    li {
      margin-bottom: 11px;
      color: #475569;
      line-height: 1.65;
    }

    .explanation {
      color: #334155;
      font-size: 16px;
      line-height: 1.8;
    }

    .disclaimer {
      margin-top: 24px;
      padding: 18px;
      border-radius: 14px;
      color: #64748b;
      background: rgba(255, 255, 255, 0.7);
      font-size: 13px;
      text-align: center;
    }

    .back-link {
      display: inline-block;
      margin-top: 24px;
      padding: 12px 18px;
      border-radius: 12px;
      color: white;
      background: linear-gradient(135deg, #4f46e5, #7c3aed);
      text-decoration: none;
      font-weight: 700;
    }

    .empty {
      color: #94a3b8;
    }

    @media (max-width: 900px) {
      .summary-grid {
        grid-template-columns: repeat(2, 1fr);
      }

      .content-grid {
        grid-template-columns: 1fr;
      }

      .card.full {
        grid-column: auto;
      }
    }

    @media (max-width: 520px) {
      h1 {
        font-size: 32px;
      }

      .summary-grid {
        grid-template-columns: 1fr;
      }
    }
  </style>
</head>

<body>
  <main class="container">
    <header class="hero">
      <div class="eyebrow">Multi-Agent Financial Intelligence</div>
      <h1>Financial Sentiment Report</h1>
      <p class="subtitle">
        Automated analysis of official SEC filings and recent financial news
      </p>
    </header>

    <section class="summary-grid">
      <div class="summary-card">
        <div class="summary-label">Ticker</div>
        <div class="summary-value">${escapeHtml(result.ticker)}</div>
      </div>

      <div class="summary-card">
        <div class="summary-label">Initial Sentiment</div>
        <div class="summary-value">
          ${escapeHtml(result.initial_sentiment)}
        </div>
      </div>

      <div class="summary-card">
        <div class="summary-label">Final Sentiment</div>
        <div class="sentiment ${sentimentClass}">
          ${escapeHtml(result.final_sentiment)}
        </div>
      </div>

      <div class="summary-card">
        <div class="summary-label">Confidence</div>
        <div class="summary-value">${escapeHtml(result.confidence)}</div>
      </div>

      <div class="summary-card">
        <div class="summary-label">Review Decision</div>
        <div class="summary-value">${escapeHtml(result.review_decision)}</div>
      </div>
    </section>

    <section class="content-grid">
      <article class="card">
        <h2>Important SEC Findings</h2>
        ${list(result.important_sec_findings)}
      </article>

      <article class="card">
        <h2>Important News Findings</h2>
        ${list(result.important_news_findings)}
      </article>

      <article class="card">
        <h2>Main Reasons</h2>
        ${list(result.main_reasons)}
      </article>

      <article class="card">
        <h2>Risk Factors</h2>
        ${list(result.risk_factors)}
      </article>

      <article class="card">
        <h2>Contradictions</h2>
        ${list(result.contradictions)}
      </article>

      <article class="card">
        <h2>Corrections to Initial Analysis</h2>
        ${list(result.corrections_to_initial_analysis)}
      </article>

      <article class="card full">
        <h2>Final Explanation</h2>
        <div class="explanation">
          ${escapeHtml(result.final_explanation)}
        </div>
      </article>
    </section>

    <div class="disclaimer">
      Agreement with initial analyst: ${agreementText}<br><br>
      ${escapeHtml(result.disclaimer)}
    </div>

    <div style="text-align:center;">
      <a
        class="back-link"
        href="http://localhost:5678/webhook/financial-analysis"
      >
        Analyze Another Stock
      </a>
    </div>
  </main>
</body>
</html>
`;

return [
  {
    json: {
      html
    }
  }
];
